async function submitContactForm(formData)
{
  try{
    let res = await fetch("https://formsubmit.co/sidhuc888@gmail.com",{
      method:"POST",
      headers:{"Content-Type":"application/json"},
      body:JSON.stringify(formData)
    });
    let data = await res.text();          // .json()giving error of token<
    console.log(data);
  }
  catch(err)
  {
    console.log(err);
  }

}

submitContactForm({ name: "Bob", email: "bob@example.com", message: "Hello, I need help!" });


